<p class="wp-block-paragraph">In short, the Directorate of Immigration Management provides serious support to make life easier for students in Turkey. If you do your procedures correctly and on time, your education life in Turkey will be much more enjoyable and trouble-free.</p>', '$.wp_published_at', '2025-10-14T13:47:07Z', '$.wp_modified_at', '2026-03-15T18:40:17Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2025/06/directorate-of-migration-management-in-turkiye.webp","alt":"Foreign man holding residence permit outside immigration office","title":"directorate-of-migration-management-in-turkiye"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'en' AND "slug" = 'directorate-of-immigration-administration' );
