-universitesi-hukuk-fakultesi/#schema-5999","isPartOf":{"@id":"https://roadtostudy.com/ozyegin-universitesi-hukuk-fakultesi/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/ozyegin-universitesi-hukuk-fakultesi/#webpage"}},{"@type":"VideoObject","name":"Özyeğin Hukuk 50 Burslu Fiyatları | Road to Study","description":"Enjoy the videos and music you love, upload original content, and share it all with friends, family, and the world on YouTube.","uploadDate":"2025-06-04T09:12:50+03:00","thumbnailUrl":"https://roadtostudy.com/wp-content/uploads/2025/06/ozyegin-universitesi-hukuk-fakultesi.webp","embedUrl":"https://www.youtube.com/embed/UCeMMumli2w","isFamilyFriendly":"True","@id":"https://roadtostudy.com/ozyegin-universitesi-hukuk-fakultesi/#schema-6000","isPartOf":{"@id":"https://roadtostudy.com/ozyegin-universitesi-hukuk-fakultesi/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/ozyegin-universitesi-hukuk-fakultesi/#webpage"}}]}]}'), '$.content_html', '<figure class="wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio"><div class="wp-block-embed__wrapper">
