dtostudy.com/#person"},"inLanguage":"en-US"},{"@type":"ImageObject","@id":"https://roadtostudy.com/wp-content/uploads/2025/10/the-e-residency-system-in-turkey.webp","url":"https://roadtostudy.com/wp-content/uploads/2025/10/the-e-residency-system-in-turkey.webp","width":"1168","height":"880","inLanguage":"en-US"},{"@type":"WebPage","@id":"https://roadtostudy.com/en/the-e-residency-system-in-turkey/#webpage","url":"https://roadtostudy.com/en/the-e-residency-system-in-turkey/","name":"The e-Residency System in Turkey: Follow-up and New Rules","datePublished":"2025-10-22T13:39:37+03:00","dateModified":"2026-03-15T21:50:08+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"primaryImageOfPage":{"@id":"https://roadtostudy.com/wp-content/uploads/2025/10/the-e-residency-system-in-turkey.webp"},"inLanguage":"en-US"},{"@type":"Person","@id":"https://roadtostudy.com/en/author/murat/","name":"Murat","url":"https://roadtostudy.com/en/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"en-US"}},{"@type":"BlogPosting","headline":"The e-Residency System in Turkey: Follow-up and New Rules","keywords":"e-Residency","datePublished":"2025-10-22T13:39:37+03:00","dateModified":"2026-03-15T21:50:08+03:00","articleSection":"Visa and Immigration","author":{"@id":"https://roadtostudy.com/en/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"If you have come to Turkey as a student or want to live there for the long term, obtaining a residence permit is a must. Fortunately, thanks to the","name":"The e-Residency System in Turkey: Follow-up and New Rules","@id":"https://roadtostudy.com/en/the-e-residency-system-in-turkey/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/en/the-e-residency-system-in-turkey/#webpage"},"image":{"@id":"https://roadtostudy.com/wp-content/uploads/2025/10/the-e-residency-system-in-turkey.webp"},"inLanguage":"en-US","mainEntityOfPage":{"@id":"https://roadtostudy.com/en/the-e-residency-system-in-turkey/#webpage"}}]}]}', "content_html" = '<p class="wp-block-paragraph">If you have come to Turkey as a student or want to live there for the long term, obtaining a residence permit is a must. Fortunately, thanks to the e-Residency system, applications are now made online and your card is sent to your address via PTT. In this article, I will explain step by step how to track your e-residency card in Turkey and how to find out the result of your application. Let&#8217;s start if you are ready!</p>


<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>
<hr class="wp-block-separator has-alpha-channel-opacity" >
<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>


<h2 class="wp-block-heading" id="how-to-track-your-e-residence-card">How to Track Your e-Residence Card</h2>



<p class="wp-block-paragraph">After your application for a residence permit in Turkey is approved, the Immigration Administration prints your ID card and sends it to your address via PTT. At this stage, the most frequently asked questions are &#8220;When will my card arrive?&#8221; and &#8220;How can I find out the shipment status?&#8221;</p>



<p class="wp-block-paragraph">When your card is shipped, PTT will send an SMS to your cell phone. This message includes the date your card was sent, the estimated delivery time and, most importantly, the shipment tracking number. After receiving this number, you can check the status of your card via <strong><a class="" href="https://gonderitakip.ptt.gov.tr/" target="_blank" rel="noopener">PTT Cargo Tracking System</a></strong>. After logging into the system, you can easily find out which branch your shipment is in or whether it is on its way by entering your tracking number.</p>



<p class="wp-block-paragraph">Card delivery time is usually between 1 and 2 weeks. However, during peak periods (e.g. September-October) this time may be slightly longer. If your card is not delivered or you do not receive an SMS, do not panic! You can check your application number by logging into the e-Residency system immediately.</p>



<p class="wp-block-paragraph"><strong>Important Notice:</strong> Remember to carry your old residence permit or student visa document with you until the card is delivered. Because you may need to show this document in some checks and you will not have any problems if your card has not yet arrived.</p>



<p class="wp-block-paragraph">If you have applied or are planning to apply for a residence permit for your family members, the process may be slightly different. For detailed information on this subject, be sure to check out my article <strong><a href="https://roadtostudy.com/en/what-is-a-family-residence-permit-in-turkey/" data-type="link" data-id="https://roadtostudy.com/en/what-is-a-family-residence-permit-in-turkey/">Visa and Residence Permit Options for Family Members in Turkey</a></strong>.</p>


<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>
<hr class="wp-block-separator has-alpha-channel-opacity" >
<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>


<h2 class="wp-block-heading" id="how-to-learn-residence-permit-application-result">How to Learn Residence Permit Application Result</h2>



<p class="wp-block-paragraph">Once you have submitted your application, the most exciting (and sometimes the most stressful) part is finding out if your residence permit application has been approved or what stage it is at. To understand and control this process, the official <strong><a class="" href="https://e-ikamet.goc.gov.tr/" target="_blank" rel="noopener">e-Residency Portal</a></strong> of the Directorate of Migration Management is really helpful.</p>



<p class="wp-block-paragraph">The steps you need to follow to find out what stage your application is at are actually quite easy, but can be confusing if it&#8217;s your first time.</p>



<h3 class="wp-block-heading" id="application-result-learning">Application Result Learning</h3>



<ol class="wp-block-list">
<li><strong>Log in to the e-Residence System.</strong><br>Go to e-ikamet.goc.gov.tr and click on &#8220;Application Status Inquiry&#8221; at the top of the page.</li>



<li><strong>Enter your Application Number or Identity Information.</strong><br>Enter your application number or Turkish ID number (or passport number if you don&#8217;t have one) and let the system recognize you.</li>



<li><strong>See What Stage Your Application Is At.</strong><br></li>



<li><strong>If necessary, upload additional documents to the system or make an appointment.</strong><br>If it says &#8220;Additional Document Requested&#8221;, you may need to upload your missing documents to the system or make an appointment with the Provincial Directorate of Migration Management.</li>
</ol>



<p class="wp-block-paragraph">My advice: Do not panic immediately when you see &#8220;in process&#8221; in the system. Especially in periods such as September-October, when the number of applications is very high, the process can be a bit slow.</p>



<p class="wp-block-paragraph">If the result of your application has been pending for too long (e.g. no change for 1-2 months), you can get information directly from the Provincial Directorate of Migration Management.</p>



<p class="wp-block-paragraph">While following this process, if you are wondering whether you can get a work permit in Turkey as a student, be sure to take a look at my article <strong><a href="https://roadtostudy.com/en/obtaining-a-work-permit-with-a-student-visa/" data-type="link" data-id="https://roadtostudy.com/en/obtaining-a-work-permit-with-a-student-visa/">Can I Get a Work Permit in Turkey with a Student Visa?</a></strong>. So you can make your education and work plans more clearly.</p>


<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>
<hr class="wp-block-separator has-alpha-channel-opacity" >
<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>


<h2 class="wp-block-heading" id="new-rules-for-long-term-residence-permit-in-turkey">New Rules for Long Term Residence Permit in Turkey</h2>



<p class="wp-block-paragraph">As of 2025, some new rules have been introduced to obtain a long-term residence permit in Turkey. You now need to prepare the following documents in full when making your application:</p>



<ul class="wp-block-list">
<li>Valid passport</li>



<li>Application form</li>



<li>Two passport-sized photos</li>



<li>Document showing that you do not receive social assistance from the Turkish authorities</li>



<li>Proof of funding showing that you have sufficient financial resources</li>



<li>Proof of real estate leased or purchased in Turkey</li>



<li>Previous residence permit</li>



<li>Health insurance</li>
</ul>



<p class="wp-block-paragraph">If you prepare these documents completely and upload them to the e-residency system, it is possible to finalize your application faster.</p>


<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>
<hr class="wp-block-separator has-alpha-channel-opacity" >
<div style="height:23px" aria-hidden="true" class="wp-block-spacer"></div>


<h2 class="wp-block-heading" id="frequently-asked-questions">Frequently Asked Questions</h2>


<h3 class="wp-block-heading">


<h3 class="wp-block-heading wp-block-paragraph">What should foreigners who stay in Turkey for more than 90 days do?</h3>



<p class="wp-block-paragraph">Foreigners exceeding 90 days must apply for a residence permit.</p>


<h3 class="wp-block-heading">


<h3 class="wp-block-heading wp-block-paragraph">How many days after the residence permit is approved?</h3>



<p class="wp-block-paragraph">The approved residence permit is usually delivered within 10-15 working days.</p>



