sity Department of Business Administration","articleSection":"University and Programs","@id":"https://roadtostudy.com/en/ozyegin-university-business-administration/#schema-11649","isPartOf":{"@id":"https://roadtostudy.com/en/ozyegin-university-business-administration/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"en-US","mainEntityOfPage":{"@id":"https://roadtostudy.com/en/ozyegin-university-business-administration/#webpage"}},{"@type":"VideoObject","name":"Özyeğin University Department of Business Administration","description":"Enjoy the videos and music you love, upload original content, and share it all with friends, family, and the world on YouTube.","uploadDate":"2025-07-23T14:44:18+03:00","thumbnailUrl":"https://roadtostudy.com/wp-content/uploads/2025/06/ozyegin-universitesi-isletme-school.webp","embedUrl":"https://www.youtube.com/embed/r2IZK4-joDM","isFamilyFriendly":"True","@id":"https://roadtostudy.com/en/ozyegin-university-business-administration/#schema-11650","isPartOf":{"@id":"https://roadtostudy.com/en/ozyegin-university-business-administration/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"en-US","mainEntityOfPage":{"@id":"https://roadtostudy.com/en/ozyegin-university-business-administration/#webpage"}}]}]}', "content_html" = '<figure class="wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio"><div class="wp-block-embed__wrapper">
