ramlar","@id":"https://roadtostudy.com/ozyegin-universitesi-psikoloji-bolumu/#schema-7058","isPartOf":{"@id":"https://roadtostudy.com/ozyegin-universitesi-psikoloji-bolumu/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/ozyegin-universitesi-psikoloji-bolumu/#webpage"}},{"@type":"VideoObject","name":"Özyeğin Üniversitesi Psikoloji Bölümü: %50 Burs Seçenekleri","description":"Enjoy the videos and music you love, upload original content, and share it all with friends, family, and the world on YouTube.","uploadDate":"2025-06-16T17:01:20+03:00","thumbnailUrl":"https://roadtostudy.com/wp-content/uploads/2025/06/ozyegin-universitesi-psikoloji.webp","embedUrl":"https://www.youtube.com/embed/Z_49RT5lTMc","isFamilyFriendly":"True","@id":"https://roadtostudy.com/ozyegin-universitesi-psikoloji-bolumu/#schema-7059","isPartOf":{"@id":"https://roadtostudy.com/ozyegin-universitesi-psikoloji-bolumu/#webpage"},"publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/ozyegin-universitesi-psikoloji-bolumu/#webpage"}}]}]}', "content_html" = '<figure class="wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio"><div class="wp-block-embed__wrapper">
